function solve(s) {
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    const uniqueChars = Array.from(freq.keys());
    let totalDifference = 0;
    const processedPairs = new Set();

    /**
     * Calculates the mirror character.
     * @param {string} char 
     * @returns {string} The mirror character.
     */
    const getMirror = (char) => {
        if (char >= 'a' && char <= 'z') {
            // Lowercase letter: 'a' -> 'z', 'b' -> 'y', etc.
            const code = char.charCodeAt(0);
            // 'a' is 97, 'z' is 122. Mirror code = 97 + 122 - code
            const mirrorCode = 'a'.charCodeAt(0) + 'z'.charCodeAt(0) - code;
            return String.fromCharCode(mirrorCode);
        } else if (char >= '0' && char <= '9') {
            // Digit: '0' -> '9', '1' -> '8', etc.
            const code = char.charCodeAt(0);
            // '0' is 48, '9' is 57. Mirror code = 48 + 57 - code
            const mirrorCode = '0'.charCodeAt(0) + '9'.charCodeAt(0) - code;
            return String.fromCharCode(mirrorCode);
        }
        // Should not happen based on problem constraints
        return null;
    };

    for (const char of uniqueChars) {
        const m = getMirror(char);

        // Canonical representation for the pair to ensure we count each pair only once.
        // We sort the pair alphabetically/lexicographically.
        const pairKey = char < m ? `${char}-${m}` : `${m}-${char}`;

        if (processedPairs.has(pairKey)) {
            continue;
        }

        processedPairs.add(pairKey);

        const freqC = freq.get(char) || 0;
        const freqM = freq.get(m) || 0;

        // The problem states: "镜像对 (c, m) 和 (m, c) 被视为相同，只能被计算一次。"
        // If c == m (e.g., 'm' -> 'n' if m='n', or a palindromic character if one existed, but here they are symmetric), 
        // we still count the difference for (c, c).

        totalDifference += Math.abs(freqC - freqM);
    }

    return totalDifference;
}

